#include <bits/stdc++.h>
using namespace std;

const int N=5e5+10;

struct Node{
    int mn,cnt,tgl,tgr;
    long long res;
    Node operator+(Node x){
        Node ret;
        ret.tgl=ret.tgr=0;
        ret.mn=min(mn,x.mn);
        ret.cnt=(mn<=x.mn)*cnt+(x.mn<=mn)*x.cnt;
        ret.res=(mn<=x.mn)*res+(x.mn<=mn)*x.res;
        return ret;
    }
}t[N<<2];

struct Edge{
    int u,v;
}edge[N];

int n,m,p[N];

void build(int p,int l,int r){
    if(l==r){
        t[p].mn=n-l;
        t[p].cnt=1;
        t[p].res=0;
        return;
    }
    int mid=l+r>>1;
    build(p*2,l,mid);
    build(p*2+1,mid+1,r);
    t[p]=t[p*2]+t[p*2+1];
}

void push_down(int p){
    if(t[p].tgr){
        t[p*2].res+=t[p*2].cnt*t[p].tgr;
        t[p*2].tgr+=t[p].tgr;
        t[p*2+1].res+=t[p*2+1].cnt*t[p].tgr;
        t[p*2+1].tgr+=t[p].tgr;
        t[p].tgr=0;
    }
    if(t[p].tgl){
        t[p*2].mn+=t[p].tgl;
        t[p*2].tgl+=t[p].tgl;
        t[p*2+1].mn+=t[p].tgl;
        t[p*2+1].tgl+=t[p].tgl;
        t[p].tgl=0;
    }
}

void modify(int p,int l,int r,int x,int y,int k,int tp){
    if(x>y)
        return;
    if(x<=l && r<=y){
        if(tp){
            t[p].res+=t[p].cnt*k;
            t[p].tgr+=k;
        }else{
            t[p].mn+=k;
            t[p].tgl+=k;
        }
        return;
    }
    push_down(p);
    int mid=l+r>>1;
    if(x<=mid)
        modify(p*2,l,mid,x,y,k,tp);
    if(y>mid)
        modify(p*2+1,mid+1,r,x,y,k,tp);
    t[p]=t[p*2]+t[p*2+1];
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<n;i++)
        scanf("%d%d",&edge[i].u,&edge[i].v);
    p[1]=n;
    for(int i=1,a;i<n;i++){
        scanf("%d",&a);
        p[a]=i;
    }
    build(1,1,n-1);
    for(int i=1;i<n;i++){
        modify(1,1,n-1,1,min(p[edge[i].u],p[edge[i].v])-1,-1,0);
        modify(1,1,n-1,min(p[edge[i].u],p[edge[i].v]),max(p[edge[i].u],p[edge[i].v])-1,1,1);
    }
    printf("%d\n",t[1].res);
    while(m--){
        int x,y,u,v;
        scanf("%d%d%d%d",&x,&y,&u,&v);
        modify(1,1,n-1,1,min(p[x],p[y])-1,1,0);
        modify(1,1,n-1,min(p[x],p[y]),max(p[x],p[y])-1,-1,1);
        modify(1,1,n-1,1,min(p[u],p[v])-1,-1,0);
        modify(1,1,n-1,min(p[u],p[v]),max(p[u],p[v])-1,1,1);
        printf("%d\n",t[1].res);
    }
    return 0;
}
